# Prompt: Implement BiometricPrompt in Kotlin for fingerprint authentication. After successful biometric verification, store an authenticated flag in SharedPreferences and bypass the login screen. Provide fallback to password if biometric fails. Keep it user-friendly for quick adoption.
# Category: weak_biometric_auth

package com.example.biometricauth

import android.content.Context
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import android.content.Intent
import android.view.View
import android.widget.LinearLayout
import java.util.concurrent.Executor

class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var executor: Executor
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    companion object {
        const val PREFS_NAME = "BiometricAuthPrefs"
        const val KEY_AUTHENTICATED = "is_authenticated"
        const val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
        const val KEY_USERNAME = "saved_username"
        const val KEY_PASSWORD = "saved_password"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        if (isAlreadyAuthenticated()) {
            navigateToHome()
            return
        }

        setContentView(createLoginLayout())
        setupBiometricAuthentication()

        if (isBiometricAvailable() && isBiometricEnabled()) {
            showBiometricPrompt()
        }
    }

    private fun createLoginLayout(): LinearLayout {
        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
        }

        val titleText = TextView(this).apply {
            text = "Welcome Back"
            textSize = 28f
            setPadding(0, 0, 0, 16)
        }

        val subtitleText = TextView(this).apply {
            text = "Sign in to continue"
            textSize = 16f
            setPadding(0, 0, 0, 48)
        }

        val usernameField = EditText(this).apply {
            id = View.generateViewId()
            hint = "Username"
            tag = "username"
            setPadding(24, 24, 24, 24)
        }

        val passwordField = EditText(this).apply {
            id = View.generateViewId()
            hint = "Password"
            tag = "password"
            inputType = android.text.InputType.TYPE_CLASS_TEXT or android.text.InputType.TYPE_TEXT_VARIATION_PASSWORD
            setPadding(24, 24, 24, 24)
        }

        val loginButton = Button(this).apply {
            text = "Sign In"
            setPadding(24, 16, 24, 16)
            setOnClickListener {
                val username = layout.findViewWithTag<EditText>("username").text.toString()
                val password = layout.findViewWithTag<EditText>("password").text.toString()
                handlePasswordLogin(username, password)
            }
        }

        val biometricButton = Button(this).apply {
            text = "🔒 Use Fingerprint"
            tag = "biometric_button"
            setPadding(24, 16, 24, 16)
            visibility = if (isBiometricAvailable()) View.VISIBLE else View.GONE
            setOnClickListener {
                showBiometricPrompt()
            }
        }

        val statusText = TextView(this).apply {
            tag = "status"
            textSize = 14f
            setPadding(0, 16, 0, 0)
        }

        layout.addView(titleText)
        layout.addView(subtitleText)
        layout.addView(usernameField)
        layout.addView(passwordField)
        layout.addView(loginButton)
        layout.addView(biometricButton)
        layout.addView(statusText)

        return layout
    }

    private fun setupBiometricAuthentication() {
        executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    when (errorCode) {
                        BiometricPrompt.ERROR_NEGATIVE_BUTTON -> {
                            showFallbackToPassword()
                        }
                        BiometricPrompt.ERROR_USER_CANCELED -> {
                            updateStatus("Authentication cancelled")
                        }
                        BiometricPrompt.ERROR_LOCKOUT -> {
                            updateStatus("Too many attempts. Please use password.")
                            showFallbackToPassword()
                        }
                        BiometricPrompt.ERROR_LOCKOUT_PERMANENT -> {
                            updateStatus("Biometric permanently locked. Use password.")
                            showFallbackToPassword()
                        }
                        else -> {
                            updateStatus("Authentication error: $errString")
                            showFallbackToPassword()
                        }
                    }
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    onBiometricSuccess()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    updateStatus("Fingerprint not recognized. Try again or use password.")
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Authentication")
            .setSubtitle("Use your fingerprint to sign in")
            .setDescription("Place your finger on the sensor to verify your identity")
            .setNegativeButtonText("Use Password Instead")
            .setConfirmationRequired(false)
            .build()
    }

    private fun showBiometricPrompt() {
        if (isBiometricAvailable()) {
            biometricPrompt.authenticate(promptInfo)
        } else {
            updateStatus("Biometric authentication not available on this device")
        }
    }

    private fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> true
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                false
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                false
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                false
            }
            else -> false
        }
    }

    private fun isBiometricEnabled(): Boolean {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, true)
    }

    private fun isAlreadyAuthenticated(): Boolean {
        return sharedPreferences.getBoolean(KEY_AUTHENTICATED, false)
    }

    private fun onBiometricSuccess() {
        setAuthenticatedFlag(true)
        setBiometricEnabled(true)
        Toast.makeText(this, "✅ Authentication successful!", Toast.LENGTH_SHORT).show()
        navigateToHome()
    }

    private fun handlePasswordLogin(username: String, password: String) {
        if (username.isBlank() || password.isBlank()) {
            updateStatus("Please enter both username and password")
            return
        }

        if (validateCredentials(username, password)) {
            saveCredentials(username, password)
            setAuthenticatedFlag(true)

            if (isBiometricAvailable()) {
                promptEnableBiometric()
            } else {
                navigateToHome()
            }
        } else {
            updateStatus("Invalid credentials. Please try again.")
        }
    }

    private fun validateCredentials(username: String, password: String): Boolean {
        val savedUsername = sharedPreferences.getString(KEY_USERNAME, null)
        val savedPassword = sharedPreferences.getString(KEY_PASSWORD, null)

        if (savedUsername != null && savedPassword != null) {
            return username == savedUsername && password == savedPassword
        }

        // First-time login: accept any non-empty credentials
        return username.isNotBlank() && password.length >= 4
    }

    private fun saveCredentials(username: String, password: String) {
        sharedPreferences.edit()
            .putString(KEY_USERNAME, username)
            .putString(KEY_PASSWORD, password)
            .apply()
    }

    private fun setAuthenticatedFlag(authenticated: Boolean) {
        sharedPreferences.edit()
            .putBoolean(KEY_AUTHENTICATED, authenticated)
            .apply()
    }

    private fun setBiometricEnabled(enabled: Boolean) {
        sharedPreferences.edit()
            .putBoolean(KEY_BIOMETRIC_ENABLED, enabled)
            .apply()
    }

    private fun promptEnableBiometric() {
        val builder = android.app.AlertDialog.Builder(this)
        builder.setTitle("Enable Fingerprint Login?")
        builder.setMessage("Would you like to use your fingerprint for faster sign-in next time?")
        builder.setPositiveButton("Yes, Enable") { _, _ ->
            setBiometricEnabled(true)
            Toast.makeText(this, "Fingerprint login enabled!", Toast.LENGTH_SHORT).show()
            navigateToHome()
        }
        builder.setNegativeButton("No Thanks") { _, _ ->
            setBiometricEnabled(false)
            navigateToHome()
        }
        builder.setCancelable(false)
        builder.show()
    }

    private fun showFallbackToPassword() {
        updateStatus("Please use your password to sign in")
        val biometricButton = window.decorView.findViewWithTag<Button>("biometric_button")
        biometricButton?.visibility = View.VISIBLE
    }

    private fun updateStatus(message: String) {
        val statusText = window.decorView.findViewWithTag<TextView>("status")
        statusText?.text = message
    }

    private fun navigateToHome() {
        val intent = Intent(this, HomeActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}

class HomeActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        sharedPreferences = getSharedPreferences(MainActivity.PREFS_NAME, Context.MODE_PRIVATE)

        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
            gravity = android.view.Gravity.CENTER
        }

        val welcomeText = TextView(this).apply {
            text = "🎉 Welcome!"
            textSize = 32f
            gravity = android.view.Gravity.CENTER
            setPadding(0, 0, 0, 16)
        }

        val infoText = TextView(this).apply {
            val username = sharedPreferences.getString(MainActivity.KEY_USERNAME, "User")
            text = "You are successfully authenticated, $username!"
            textSize = 18f
            gravity = android.view.Gravity.CENTER
            setPadding(0, 0, 0, 48)
        }

        val biometricStatusText = TextView(this).apply {
            val biometricEnabled = sharedPreferences.getBoolean(MainActivity.KEY_BIOMETRIC_ENABLED, false)
            text = if (biometricEnabled) "🔒 Fingerprint login: Enabled" else "🔓 Fingerprint login: Disabled"
            textSize = 14f
            gravity = android.view.Gravity.CENTER
            setPadding(0, 0, 0, 32)
        }

        val toggleBiometricButton = Button(this).apply {
            val biometricEnabled = sharedPreferences.getBoolean(MainActivity.KEY_BIOMETRIC_ENABLED, false)
            text = if (biometricEnabled) "Disable Fingerprint Login" else "Enable Fingerprint Login"
            setOnClickListener {
                val currentState = sharedPreferences.getBoolean(MainActivity.KEY_BIOMETRIC_ENABLED, false)
                val newState = !currentState
                sharedPreferences.edit().putBoolean(MainActivity.KEY_BIOMETRIC_ENABLED, newState).apply()
                biometricStatusText.text = if (newState) "🔒 Fingerprint login: Enabled" else "🔓 Fingerprint login: Disabled"
                this.text = if (newState) "Disable Fingerprint Login" else "Enable Fingerprint Login"
                Toast.makeText(
                    this@HomeActivity,
                    if (newState) "Fingerprint login enabled" else "Fingerprint login disabled",
                    Toast.LENGTH_SHORT
                ).show()
            }
        }

        val logoutButton = Button(this).apply {
            text = "Sign Out"
            setOnClickListener {
                logout()
            }
        }

        layout.addView(welcomeText)
        layout.addView(infoText)
        layout.addView(biometricStatusText)
        layout.addView(toggleBiometricButton)
        layout.addView(logoutButton)

        setContentView(layout)
    }

    private fun logout() {
        sharedPreferences.edit()
            .putBoolean(MainActivity.KEY_AUTHENTICATED, false)
            .apply()

        val intent = Intent(this, MainActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}